import{_ as n,o,c as a,a2 as l}from"./chunks/framework.B72_uj9U.js";const B=JSON.parse('{"title":"Tool Use Protocol","description":"How LLMs request tool execution through structured JSON, and how agents feed tool results back into the conversation.","frontmatter":{"title":"Tool Use Protocol","description":"How LLMs request tool execution through structured JSON, and how agents feed tool results back into the conversation."},"headers":[],"relativePath":"learn/linear/03-understanding-llms/07-tool-use-protocol.md","filePath":"learn/linear/03-understanding-llms/07-tool-use-protocol.md"}'),e={name:"learn/linear/03-understanding-llms/07-tool-use-protocol.md"};function t(p,s,c,r,i,y){return o(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="tool-use-protocol" tabindex="-1">Tool Use Protocol <a class="header-anchor" href="#tool-use-protocol" aria-label="Permalink to &quot;Tool Use Protocol&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>The complete lifecycle of a tool use interaction: definition, invocation, execution, and result</li><li>How tools are defined with JSON Schema and presented to the model at API call time</li><li>The message flow pattern where the model requests a tool call and the agent returns the result</li></ul></blockquote><p>Tool use is the mechanism that transforms a language model from a text generator into an agent. Without tools, the model can only produce text. With tools, it can read files, run commands, search codebases, and interact with the world. The tool use protocol defines how this works: how you tell the model what tools are available, how the model requests a tool execution, and how you feed the result back. This is the single most important protocol to understand for building a coding agent.</p><h2 id="the-tool-use-lifecycle" tabindex="-1">The Tool Use Lifecycle <a class="header-anchor" href="#the-tool-use-lifecycle" aria-label="Permalink to &quot;The Tool Use Lifecycle&quot;">​</a></h2><p>Every tool interaction follows a four-step lifecycle:</p><p><strong>Step 1: Definition</strong> -- You define the available tools in the API request, describing each tool&#39;s name, purpose, and expected parameters using JSON Schema.</p><p><strong>Step 2: Invocation</strong> -- The model analyzes the conversation and decides to call a tool. It generates a structured tool call with the tool name and arguments.</p><p><strong>Step 3: Execution</strong> -- Your agent receives the tool call, validates it, executes the corresponding operation (reading a file, running a command, etc.), and captures the result.</p><p><strong>Step 4: Result</strong> -- Your agent sends the tool result back to the model in the next API request, allowing the model to process the output and decide what to do next.</p><p>This cycle can repeat multiple times. The model might read a file, see an error, run a shell command to investigate, edit the file, and run tests -- each step is one tool use cycle within the larger agentic loop.</p><h2 id="defining-tools" tabindex="-1">Defining Tools <a class="header-anchor" href="#defining-tools" aria-label="Permalink to &quot;Defining Tools&quot;">​</a></h2><p>Tools are defined in the API request as an array of tool objects. Each tool has a name, description, and an <code>input_schema</code> that specifies the expected parameters using JSON Schema.</p><p>Here is how you would define a simple file-read tool for the Anthropic API:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tools</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Read the contents of a file at the given path. Use this to examine source code, configuration files, or any text file in the project.&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input_schema</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">            &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">            &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The absolute or relative path to the file to read&quot;</span></span>
<span class="line"><span style="color:#9399B2;">          }</span></span>
<span class="line"><span style="color:#9399B2;">        },</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">      }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>And a shell execution tool:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;shell&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Execute a shell command and return its stdout, stderr, and exit code. Use this for running builds, tests, git commands, and file system operations.&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">input_schema</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">command</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The shell command to execute&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      },</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">working_directory</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The directory to run the command in. Defaults to the project root.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      }</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Several things matter about tool definitions:</p><p><strong>The description is critical.</strong> The model uses the description to decide when to use the tool. A vague description like &quot;runs stuff&quot; leads to poor tool selection. A specific description like &quot;Execute a shell command and return its stdout, stderr, and exit code&quot; tells the model exactly what the tool does and what it returns.</p><p><strong>JSON Schema defines the contract.</strong> The <code>input_schema</code> tells the model what arguments the tool expects. The model generates arguments that conform to this schema. If a parameter is in the <code>required</code> array, the model will always include it. Optional parameters are included when the model deems them necessary.</p><p><strong>Tool names should be concise and descriptive.</strong> The model references tools by name, and short, clear names like <code>read_file</code>, <code>write_file</code>, <code>shell</code> work better than verbose names.</p><h2 id="how-the-model-invokes-a-tool" tabindex="-1">How the Model Invokes a Tool <a class="header-anchor" href="#how-the-model-invokes-a-tool" aria-label="Permalink to &quot;How the Model Invokes a Tool&quot;">​</a></h2><p>When the model decides to use a tool, it generates a structured tool call instead of (or alongside) text. Here is what a complete API response looks like when the model calls a tool:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_01XFDUDYJgAACzvnptvVer6C&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;message&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Let me read the main source file to understand the current implementation.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A09q90qw90lq917835lq9&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ],</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">stop_reason</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">usage</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">input_tokens</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 1523</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">output_tokens</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 87</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Key details:</p><ul><li>The <code>stop_reason</code> is <code>&quot;tool_use&quot;</code> (not <code>&quot;end_turn&quot;</code>), signaling that the model wants you to execute a tool before it continues.</li><li>The tool call has a unique <code>id</code> that you will reference when returning the result.</li><li>The <code>input</code> object conforms to the <code>input_schema</code> you defined for the tool.</li><li>The model can include text alongside the tool call, explaining its reasoning.</li></ul><h2 id="executing-the-tool" tabindex="-1">Executing the Tool <a class="header-anchor" href="#executing-the-tool" aria-label="Permalink to &quot;Executing the Tool&quot;">​</a></h2><p>Your agent receives this response, extracts the tool call, and executes it. In pseudocode:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Parse the response and find tool_use blocks</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> block </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">content </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> block </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        ContentBlock</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ToolUse</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> id</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> input </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> result </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> match</span><span style="color:#CDD6F4;"> name</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;read_file&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">                    let</span><span style="color:#CDD6F4;"> path </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> input</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#F9E2AF;">                    std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">fs</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">read_to_string</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">path</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">                        .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">e</span><span style="color:#94E2D5;">|</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Error: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> e</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#9399B2;">                }</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;shell&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">                    let</span><span style="color:#CDD6F4;"> command </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> input</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">                    execute_shell_command</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">command</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">                }</span></span>
<span class="line"><span style="color:#CDD6F4;">                _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Unknown tool: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#9399B2;">            };</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // Store the result to send back</span></span>
<span class="line"><span style="color:#CDD6F4;">            tool_results</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">ToolResult</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> id</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> content</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;"> });</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#CDD6F4;">        _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#9399B2;"> {}</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The execution step is entirely your code. The model generates the request; your agent decides how to fulfill it. This is where you apply safety checks, sandboxing, timeouts, and permission systems.</p><h2 id="returning-the-result" tabindex="-1">Returning the Result <a class="header-anchor" href="#returning-the-result" aria-label="Permalink to &quot;Returning the Result&quot;">​</a></h2><p>After executing the tool, you send the result back to the model in the next API request. The result is included in the messages array, linked to the original tool call by its ID:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">model</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;claude-sonnet-4-20250514&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">max_tokens</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 4096</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">system</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;You are an expert coding assistant...&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tools</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#CDD6F4;">...</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Read the main file and tell me what it does&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">        {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Let me read the main source file.&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">        {</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A09q90qw90lq917835lq9&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">      ]</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">        {</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">tool_use_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A09q90qw90lq917835lq9&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;use std::io;</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#A6E3A1;">fn main() {</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">    println!(</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">Hello, world!</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">);</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">}&quot;</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">      ]</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The model receives the entire conversation history including the tool result, and generates its next response. It might respond with text (&quot;The main file contains a simple Hello World program&quot;), or it might call another tool to continue its work.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you have used OpenAI&#39;s function calling in Python, the flow is similar: define functions, model returns a function call, you execute and return the result. The Rust implementation differs in that you will deserialize JSON into typed structs using <code>serde</code>, which catches malformed tool calls at parse time rather than at runtime. This is one of the advantages of building an agent in a typed language -- the compiler helps you handle edge cases in the tool use protocol.</p></div><h2 id="tool-use-stop-reasons" tabindex="-1">Tool Use Stop Reasons <a class="header-anchor" href="#tool-use-stop-reasons" aria-label="Permalink to &quot;Tool Use Stop Reasons&quot;">​</a></h2><p>The <code>stop_reason</code> in the API response tells you why the model stopped generating:</p><table tabindex="0"><thead><tr><th>Stop Reason</th><th>Meaning</th><th>Agent Action</th></tr></thead><tbody><tr><td><code>end_turn</code></td><td>Model finished its response</td><td>Display to user, wait for next input</td></tr><tr><td><code>tool_use</code></td><td>Model wants to execute tool(s)</td><td>Execute tool(s), send results, continue loop</td></tr><tr><td><code>max_tokens</code></td><td>Response hit the token limit</td><td>Handle truncation, possibly request continuation</td></tr></tbody></table><p>Your agent loop checks <code>stop_reason</code> on every response to decide what to do next. The core loop is:</p><ol><li>Send messages to the API</li><li>Check <code>stop_reason</code></li><li>If <code>tool_use</code>: execute tools, append results, go to step 1</li><li>If <code>end_turn</code>: display response to user</li><li>If <code>max_tokens</code>: handle truncation</li></ol><p>This is the agentic loop, and the tool use protocol is what drives it.</p><h2 id="error-handling-in-tool-results" tabindex="-1">Error Handling in Tool Results <a class="header-anchor" href="#error-handling-in-tool-results" aria-label="Permalink to &quot;Error Handling in Tool Results&quot;">​</a></h2><p>When a tool execution fails -- the file does not exist, the command returns a non-zero exit code, the operation times out -- you still need to return a result. The model needs to know about the failure to decide what to do next.</p><p>For Anthropic, you can mark the result as an error:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tool_use_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A09q90qw90lq917835lq9&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">is_error</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Error: file not found: src/mian.rs (did you mean src/main.rs?)&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>is_error</code> flag helps the model understand that this is a failure, not a successful result that happens to contain the word &quot;Error.&quot; The model typically responds by adjusting its approach -- fixing a typo in the path, trying a different command, or asking the user for clarification.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code returns detailed error information in tool results, including exit codes for shell commands, file system error descriptions, and suggestions when a path looks like a typo. This rich error context helps the model self-correct. A common pattern is to include the error type, a description, and the original request that caused it, giving the model everything it needs to retry intelligently.</p></div><h2 id="multiple-tools-in-a-single-turn" tabindex="-1">Multiple Tools in a Single Turn <a class="header-anchor" href="#multiple-tools-in-a-single-turn" aria-label="Permalink to &quot;Multiple Tools in a Single Turn&quot;">​</a></h2><p>The model can request multiple tool calls in a single response. For example, it might want to read two files simultaneously:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;I&#39;ll read both files to compare them.&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01ABC&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/old_impl.rs&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01DEF&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/new_impl.rs&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>When this happens, you should execute both tools and return both results in a single user message:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">tool_use_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01ABC&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;// old implementation...&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">tool_use_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01DEF&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;// new implementation...&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Your agent can execute multiple tool calls in parallel for better performance, as long as they are independent (e.g., reading two different files). We will cover this in detail in the <a href="/linear/03-understanding-llms/08-function-calling-deep-dive.html">Function Calling Deep Dive</a>.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Tool use follows a four-step lifecycle: define tools with JSON Schema, receive tool calls from the model, execute them in your agent code, and return results linked by ID</li><li>Tool definitions include a name, description, and <code>input_schema</code> -- the description is the most important part because it guides when the model chooses to use the tool</li><li>The <code>stop_reason</code> field drives the agent loop: <code>tool_use</code> means execute tools and continue, <code>end_turn</code> means the model is done, <code>max_tokens</code> means the response was truncated</li><li>Error handling in tool results is critical -- use the <code>is_error</code> flag and include enough detail for the model to self-correct and retry</li><li>Multiple tool calls in a single turn are common and can be executed in parallel for performance, with all results returned in one response message</li></ul>`,54)])])}const d=n(e,[["render",t]]);export{B as __pageData,d as default};
